mapper.select:
select *
from ticket t
where t.is_hot = 1
  and t.start_time >= #{start}
  and t.start_time < #{end}

select t.id as id, tr.id as train_id, tr.name as train_name, tr.code as train_number, ss.id as origin_station_id, ss.name as origin_station_name, ss.code as origin_station_code, se.id as destination_station_id, se.name as destination_station_name, se.code as destination_station_code, t.start_time as start_time, t.end_time as end_time, timestampdiff(SECOND, end_time, start_time) as duration from ticket t left join train tr on t.train_id = tr.id left join line l on t.line_id = l.id left join station ss on ss.id = l.start_station left join station se on se.id = l.end_station
and tr.id = #{trainId}
and date(t.start_time) = #{departureDate}
order by t.start_time desc
